245	export async function getForecastPortfolioSurface(
246	  organizationId: string,
247	): Promise<ForecastPortfolioSurface> {
248	  const weekAgo = new Date(Date.now() - 7 * 24 * 60 * 60 * 1000);
249	
250	  const [
251	    portfolioState,
252	    openBets,
253	    settledPaperBets,
254	    resolvedRows,
255	    openMarkets,
256	    scannedThisWeek,
257	    watchedMarkets,
258	  ] = await Promise.all([
259	    db.forecastPortfolioState.findUnique({ where: { organizationId } }),
260	    db.forecastBet.findMany({
261	      where: {
262	        organizationId,
263	        status: { in: ["PENDING", "AUTHORIZED", "CONFIRMED", "SUBMITTED", "FILLED"] },
264	      },
265	      include: {
266	        prediction: {
267	          include: {
268	            market: true,
269	            trace: true,
270	          },
271	        },
272	      },
273	      orderBy: { createdAt: "desc" },
274	      take: 100,
275	    }),
276	    db.forecastBet.findMany({
277	      where: {
278	        organizationId,
279	        mode: "PAPER",
280	        status: "SETTLED",
281	      },
282	      orderBy: { settledAt: "desc" },
283	      take: 200,
284	    }),
285	    db.forecastBet.findMany({
286	      where: {
287	        organizationId,
288	        status: "SETTLED",
289	      },
290	      include: {
291	        prediction: {
292	          include: {
293	            market: true,
294	            resolution: true,
295	          },
296	        },
297	      },
298	      orderBy: { settledAt: "desc" },
299	      take: 25,
300	    }),
301	    db.forecastMarket.findMany({
302	      where: {
303	        organizationId,
304	        status: "OPEN",
305	      },
306	      include: {
307	        predictions: {
308	          include: { trace: true },
309	          orderBy: { createdAt: "desc" },
310	          take: 1,
311	        },
312	      },
313	      orderBy: { updatedAt: "desc" },
314	      take: 30,
315	    }),
316	    db.forecastMarket.count({
317	      where: {
318	        organizationId,
319	        updatedAt: { gte: weekAgo },
320	      },
321	    }),
322	    db.watchedMarket.findMany({
323	      where: { organizationId },
324	      orderBy: { createdAt: "desc" },
325	      take: 50,
326	    }),
327	  ]);
328	
329	  const realizedPaperPnl = settledPaperBets.reduce(
330	    (sum, bet) => sum + money(bet.settlementPnlUsd),
331	    0,
332	  );
333	  const wins = settledPaperBets.filter((bet) => money(bet.settlementPnlUsd) > 0).length;
334	  const brierScores = resolvedRows
335	    .map((bet) => bet.prediction?.resolution?.brierScore)
336	    .map(decimalNumber)
337	    .filter((value): value is number => value !== null);
338	
339	  return {
340	    mode: modeState({
341	      killSwitchEngaged: Boolean(portfolioState?.killSwitchEngaged),
342	      killSwitchReason: portfolioState?.killSwitchReason ?? null,
343	    }),
344	    kpis: {
345	      hitRate: settledPaperBets.length > 0 ? wins / settledPaperBets.length : null,
346	      openPositions: openBets.length,
347	      realizedPaperPnl,
348	      runningBrier:
349	        brierScores.length > 0
350	          ? brierScores.reduce((sum, value) => sum + value, 0) / brierScores.length
351	          : portfolioState?.meanBrier90d ?? null,
352	      unrealizedPaperPnl: openBets.reduce((sum, bet) => sum + paperUnrealizedPnl(bet), 0),
353	    },
354	    openPositions: openBets.map((bet) => {
355	      const prediction = bet.prediction;
356	      const market = prediction?.market ?? null;
357	      const trace = prediction?.trace ?? null;
358	      return {
359	        avgPrice: money(bet.entryPrice),
360	        betId: bet.id,
361	        currentImpliedProb: currentSidePrice(market, bet.side),
362	        drivingPrinciples: normalizeTracePrinciples(trace?.principlesUsed),
363	        gateResults: normalizeGateResults(trace?.gateResults),
364	        lastUpdated: prediction?.updatedAt ?? bet.createdAt,
365	        marketTitle: market?.title ?? trace?.marketTitle ?? prediction?.headline ?? "Unknown market",
366	        marketUrl: market ? marketUrl(market) : null,
367	        mode: bet.mode,
368	        predictionId: bet.predictionId,
369	        side: bet.side,
370	        sizeUsd: money(bet.stakeUsd),
371	      };
372	    }),
373	    pipeline: openMarkets.map((market) => {
374	      const prediction = market.predictions[0] ?? null;
375	      const trace = prediction?.trace ?? null;
376	      const gates = normalizeGateResults(trace?.gateResults);
377	      const gateResults =
378	        gates.length > 0
379	          ? gates
380	          : [
381	              {
382	                gateName: "retrieval_queue",
383	                passed: true,
384	                reason: "awaiting the next forecast generator cycle",
385	              },
386	            ];
387	      return {
388	        category: market.category,
389	        drivingPrinciples: normalizeTracePrinciples(trace?.principlesUsed),
390	        gateResults,
391	        gateState: gateState(gateResults),
392	        lastUpdated: market.updatedAt,
393	        marketId: market.id,
394	        marketTitle: market.title,
395	        marketUrl: marketUrl(market),
396	        source: market.source,
397	      };
398	    }),
399	    recentlyResolved: resolvedRows.map((bet) => {
400	      const prediction = bet.prediction;
401	      const market = prediction?.market ?? null;
402	      return {
403	        betId: bet.id,
404	        marketTitle: market?.title ?? prediction?.headline ?? "Unknown market",
405	        marketUrl: market ? marketUrl(market) : null,
406	        outcome: prediction?.resolution?.marketOutcome ?? "UNKNOWN",
407	        ourSide: bet.side,
408	        pnlUsd: decimalNumber(bet.settlementPnlUsd),
409	        predictionId: bet.predictionId,
410	        reasoningHref: `/forecasts/${bet.predictionId}`,
411	        resolvedAt: prediction?.resolution?.resolvedAt ?? bet.settledAt,
412	      };
413	    }),
414	    watching: {
415	      kalshiCategories: csvEnv("FORECASTS_KALSHI_CATEGORIES"),
416	      polymarketCategories: csvEnv("FORECASTS_POLYMARKET_CATEGORIES"),
417	      scannedThisWeek,
418	      watchedMarkets: watchedMarkets.map((row) => ({
419	        createdAt: row.createdAt,
420	        externalId: row.externalId,
421	        id: row.id,
422	        lastConsideredAt: row.lastConsideredAt,
423	        source: row.source,
424	        status: row.status,
425	        url: row.url,
426	      })),
427	    },
428	  };
429	}
