import { redirect, notFound } from "next/navigation";
import { revalidatePath } from "next/cache";
import Link from "next/link";
import { fetchMethodVersion, downloadHref } from "@/lib/api/round3";
import { requireTenantContext } from "@/lib/tenant";

export default async function MethodVersionPage({
  params,
  searchParams,
}: {
  params: Promise<{ name: string; version: string }>;
  searchParams: Promise<{ ledger?: string }>;
}) {
  const tenant = await requireTenantContext();
  if (!tenant) redirect("/login");

  const { name, version } = await params;
  const decodedName = decodeURIComponent(name);
  const decodedVersion = decodeURIComponent(version);
  const sp = await searchParams;

  // Scoped: a method name registered in another org won't leak
  // through this URL — notFound() instead of returning that org's
  // version row.
  const method = await fetchMethodVersion(
    tenant.organizationId,
    decodedName,
    decodedVersion,
  );
  if (!method) notFound();

  async function packageMethod() {
    "use server";
    const base = process.env.PORTAL_API_BASE || "http://localhost:3000";
    const res = await fetch(`${base}/api/round3/methods/package`, {
      method: "POST",
      headers: { "Content-Type": "application/json" },
      body: JSON.stringify({ name: decodedName, version: decodedVersion }),
    });
    const data = await res.json();
    revalidatePath(`/methods/${name}/${version}`);
    redirect(`/methods/${name}/${version}?ledger=${data.ledgerEntryId || "done"}`);
  }

  async function documentMethod() {
    "use server";
    const base = process.env.PORTAL_API_BASE || "http://localhost:3000";
    const res = await fetch(`${base}/api/round3/methods/document`, {
      method: "POST",
      headers: { "Content-Type": "application/json" },
      body: JSON.stringify({ name: decodedName, version: decodedVersion }),
    });
    const data = await res.json();
    revalidatePath(`/methods/${name}/${version}`);
    redirect(`/methods/${name}/${version}?ledger=${data.ledgerEntryId || "done"}`);
  }

  return (
    <main style={{ maxWidth: "960px", margin: "0 auto", padding: "3rem 2rem" }}>
      <Link href="/methods" style={{ color: "var(--gold-dim)", fontSize: "0.75rem", textDecoration: "none" }}>
        ← Back to methods
      </Link>
      <h1
        style={{
          fontFamily: "'Cinzel', serif",
          color: "var(--gold)",
          letterSpacing: "0.08em",
          marginTop: "1rem",
        }}
      >
        {method.name}{" "}
        <span style={{ fontSize: "0.7em", color: "var(--parchment-dim)" }}>v{method.version}</span>
      </h1>

      {sp.ledger && (
        <div
          className="portal-card"
          style={{
            padding: "0.6rem 1rem",
            marginBottom: "1rem",
            borderLeft: "3px solid var(--gold)",
            fontSize: "0.8rem",
            color: "var(--gold)",
          }}
        >
          Action recorded. Ledger entry: {sp.ledger}
        </div>
      )}

      <div className="portal-card" style={{ padding: "1.25rem", marginBottom: "1.5rem" }}>
        <p style={{ color: "var(--parchment)", fontSize: "0.9rem" }}>{method.description}</p>

        {method.changelog && (
          <div style={{ marginTop: "0.75rem" }}>
            <div style={{ fontSize: "0.6rem", color: "var(--gold-dim)", textTransform: "uppercase", letterSpacing: "0.1em" }}>
              Changelog
            </div>
            <p style={{ color: "var(--parchment-dim)", fontSize: "0.85rem", marginTop: "0.25rem" }}>
              {method.changelog}
            </p>
          </div>
        )}

        {Object.keys(method.parameters).length > 0 && (
          <div style={{ marginTop: "0.75rem" }}>
            <div style={{ fontSize: "0.6rem", color: "var(--gold-dim)", textTransform: "uppercase", letterSpacing: "0.1em" }}>
              Parameters
            </div>
            <pre style={{ color: "var(--parchment-dim)", fontSize: "0.75rem", marginTop: "0.25rem", overflow: "auto" }}>
              {JSON.stringify(method.parameters, null, 2)}
            </pre>
          </div>
        )}

        <div style={{ marginTop: "0.5rem", fontSize: "0.7rem", color: "var(--parchment-dim)" }}>
          Published {method.publishedAt ? method.publishedAt.slice(0, 10) : ""} by {method.publishedBy}
        </div>
      </div>

      <div style={{ display: "flex", gap: "0.5rem", flexWrap: "wrap" }}>
        <form action={packageMethod}>
          <button type="submit" className="btn-solid" style={{ fontSize: "0.65rem" }}>
            Package method
          </button>
        </form>
        <form action={documentMethod}>
          <button type="submit" className="btn-solid" style={{ fontSize: "0.65rem" }}>
            Generate docs
          </button>
        </form>
        <a
          href={downloadHref(JSON.stringify(method, null, 2), "application/json")}
          download={`method-${decodedName}-${decodedVersion}.json`}
          className="btn"
          style={{ fontSize: "0.65rem", textDecoration: "none" }}
        >
          Download JSON
        </a>
      </div>
    </main>
  );
}

"""CLI commands for the Method Registry subsystem."""

from __future__ import annotations

import json
from typing import Optional

import click
from rich.console import Console
from rich.table import Table

console = Console()


def _get_store():
    from noosphere.cli import get_orchestrator
    return get_orchestrator(None).store


def _render(obj, as_json: bool) -> None:
    if as_json:
        click.echo(json.dumps(obj, indent=2, default=str))


@click.group("methods")
def cli() -> None:
    """Method registry: list, inspect, run, and diff registered methods."""


@cli.command("list")
@click.option("--status", "status_filter", type=str, default=None,
              help="Filter by status (experimental, active, deprecated, retired)")
@click.option("--json", "as_json", is_flag=True, help="Output as JSON")
def list_methods(status_filter: Optional[str], as_json: bool) -> None:
    """List all registered methods."""
    from noosphere.methods import REGISTRY

    methods = REGISTRY.list(status_filter=status_filter)
    if as_json:
        _render([{"name": m.name, "version": m.version, "status": m.status,
                  "type": m.method_type.value, "description": m.description}
                 for m in methods], True)
        return
    if not methods:
        console.print("[yellow]No methods registered.[/yellow]")
        return
    table = Table(title="Registered Methods", show_header=True)
    table.add_column("Name", style="cyan")
    table.add_column("Version")
    table.add_column("Status")
    table.add_column("Type")
    table.add_column("Description", max_width=50)
    for m in methods:
        table.add_row(m.name, m.version, m.status, m.method_type.value,
                      m.description[:50])
    console.print(table)


@cli.command("show")
@click.argument("ref")
@click.option("--json", "as_json", is_flag=True, help="Output as JSON")
def show_method(ref: str, as_json: bool) -> None:
    """Show details of a method. REF is name or name@version."""
    from noosphere.methods import REGISTRY

    name, version = (ref.split("@", 1) + ["latest"])[:2]
    method, _fn = REGISTRY.get(name, version=version)
    if as_json:
        _render(method.model_dump(), True)
        return
    table = Table(title=f"Method: {method.name}@{method.version}", show_header=False)
    for field in ("method_id", "name", "version", "method_type", "status",
                  "owner", "description", "rationale"):
        val = getattr(method, field)
        table.add_row(field, str(val) if not hasattr(val, "value") else val.value)
    table.add_row("preconditions", ", ".join(method.preconditions) or "—")
    table.add_row("postconditions", ", ".join(method.postconditions) or "—")
    console.print(table)


@cli.command("run")
@click.argument("ref")
@click.option("--input", "input_json", required=True, help="JSON input for the method")
@click.option("--json", "as_json", is_flag=True, help="Output as JSON")
def run_method(ref: str, input_json: str, as_json: bool) -> None:
    """Run a method. REF is name or name@version."""
    from noosphere.methods import REGISTRY

    name, version = (ref.split("@", 1) + ["latest"])[:2]
    _method, fn = REGISTRY.get(name, version=version)
    payload = json.loads(input_json)
    result = fn(payload)
    if as_json:
        _render(result if isinstance(result, (dict, list)) else str(result), True)
        return
    console.print(result)


@cli.command("diff")
@click.argument("ref_a")
@click.argument("ref_b")
@click.option("--json", "as_json", is_flag=True, help="Output as JSON")
def diff_methods(ref_a: str, ref_b: str, as_json: bool) -> None:
    """Diff two method versions. Each REF is name@version."""
    from noosphere.methods import REGISTRY

    name_a, ver_a = (ref_a.split("@", 1) + ["latest"])[:2]
    name_b, ver_b = (ref_b.split("@", 1) + ["latest"])[:2]
    m_a, _ = REGISTRY.get(name_a, version=ver_a)
    m_b, _ = REGISTRY.get(name_b, version=ver_b)
    d_a, d_b = m_a.model_dump(), m_b.model_dump()
    diffs = {k: {"old": d_a[k], "new": d_b[k]}
             for k in d_a if d_a.get(k) != d_b.get(k)}
    if as_json:
        _render(diffs, True)
        return
    if not diffs:
        console.print("[green]Methods are identical.[/green]")
        return
    table = Table(title=f"Diff: {ref_a} ↔ {ref_b}", show_header=True)
    table.add_column("Field", style="cyan")
    table.add_column("Old")
    table.add_column("New")
    for field, vals in diffs.items():
        table.add_row(field, str(vals["old"])[:60], str(vals["new"])[:60])
    console.print(table)


@cli.command("extract-candidates")
@click.option("--json", "as_json", is_flag=True, help="Output as JSON")
def extract_candidates(as_json: bool) -> None:
    """Scan the registry for candidate methods needing review."""
    from noosphere.methods import REGISTRY

    candidates = [m for m in REGISTRY.list() if m.status == "experimental"]
    if as_json:
        _render([{"name": m.name, "version": m.version, "owner": m.owner}
                 for m in candidates], True)
        return
    if not candidates:
        console.print("[green]No experimental candidates.[/green]")
        return
    table = Table(title="Method Candidates", show_header=True)
    table.add_column("Name", style="cyan")
    table.add_column("Version")
    table.add_column("Owner")
    for m in candidates:
        table.add_row(m.name, m.version, m.owner)
    console.print(table)

from __future__ import annotations

from typing import Callable

from noosphere.models import CascadeEdgeRelation, Method


class MethodCollisionError(Exception):
    pass


class MethodNotFoundError(Exception):
    pass


def _parse_semver(version: str) -> tuple[int, ...]:
    parts: list[int] = []
    for p in version.split("."):
        try:
            parts.append(int(p))
        except ValueError:
            parts.append(0)
    return tuple(parts)


class MethodRegistry:
    def __init__(self) -> None:
        self._specs: dict[tuple[str, str], Method] = {}
        self._fns: dict[tuple[str, str], Callable] = {}
        self._emits_edges: dict[str, list[CascadeEdgeRelation]] = {}

    def register(self, spec: Method, fn: Callable) -> None:
        key = (spec.name, spec.version)
        if key in self._specs:
            raise MethodCollisionError(
                f"Method {spec.name} v{spec.version} already registered"
            )
        self._specs[key] = spec
        self._fns[key] = fn

    def set_emits_edges(
        self, method_id: str, edges: list[CascadeEdgeRelation]
    ) -> None:
        self._emits_edges[method_id] = list(edges)

    def get_emits_edges(self, method_id: str) -> list[CascadeEdgeRelation]:
        return self._emits_edges.get(method_id, [])

    def get(
        self,
        name: str,
        version: str = "latest",
        include_retired: bool = False,
    ) -> tuple[Method, Callable]:
        if version != "latest":
            key = (name, version)
            if key not in self._specs:
                raise MethodNotFoundError(
                    f"Method {name} v{version} not found"
                )
            spec = self._specs[key]
            if spec.status == "retired" and not include_retired:
                raise MethodNotFoundError(
                    f"Method {name} v{version} is retired"
                )
            return spec, self._fns[key]

        candidates: list[tuple[str, Method]] = []
        for (n, v), spec in self._specs.items():
            if n != name:
                continue
            if spec.status == "retired" and not include_retired:
                continue
            candidates.append((v, spec))

        if not candidates:
            raise MethodNotFoundError(f"No active method found for {name}")

        candidates.sort(key=lambda x: _parse_semver(x[0]), reverse=True)
        best_version = candidates[0][0]
        return self._specs[(name, best_version)], self._fns[(name, best_version)]

    def list(self, status_filter: str | None = None) -> list[Method]:
        specs = list(self._specs.values())
        if status_filter is not None:
            specs = [s for s in specs if s.status == status_filter]
        return specs


REGISTRY = MethodRegistry()

  respondedAt DateTime?

  upload    Upload  @relation(fields: [uploadId], references: [id], onDelete: Cascade)
  requester Founder @relation(fields: [requesterId], references: [id])

  @@index([uploadId])
  @@index([requesterId])
  @@index([status])
}

// ── Conclusion — mirrors noosphere.models.Conclusion ───────────────────────

model Conclusion {
  id             String @id @default(cuid())
  organizationId String

  /// Stable id if synced from / produced for Noosphere
  noosphereId String? @unique
  text        String

  // ── Dedup key ──────────────────────────────────────────────────────
  // `normalizedText` is `LOWER(TRIM(REGEXP_REPLACE(text, '\s+', ' ')))`
  // computed once at ingest time. The ingest pipeline checks for an
  // existing Conclusion in the same org with a matching normalizedText;
  // if one exists, it adds the current upload as an ADDITIONAL source
  // via ConclusionSource rather than inserting a duplicate row. That's
  // what makes deletion correct: when two uploads produced the same
  // claim and we delete one, the conclusion stays — it's still
  // supported by the other source.
  //
  // Nullable so the column can be added to an existing DB without a
  // rewrite; the migration back-fills every existing row. Indexed
  // `(organizationId, normalizedText)` because every lookup is scoped
  // to a single org.
  normalizedText         String?
  confidenceTier         String // firm | founder | open (ConfidenceTier)
  rationale              String   @default("")
  supportingPrincipleIds String   @default("[]") // JSON string[]
  evidenceChainClaimIds  String   @default("[]")
  dissentClaimIds        String   @default("[]")
  confidence             Float    @default(0)
  topicHint              String   @default("") // UI filter / display
  createdAt              DateTime @default(now())

  /// JSON-serialized float[] embedding produced by Noosphere's sentence
  /// encoder at ingest time. Null for conclusions ingested before this
  /// column was added; the semantic explorer backfills on demand.
  embeddingJson String?

  attributedFounderId String?
  attributedFounder   Founder?                    @relation("ConclusionFounder", fields: [attributedFounderId], references: [id])
  organization        Organization                @relation(fields: [organizationId], references: [id], onDelete: Restrict)
  publicationReviews  PublicationReview[]
  sources             ConclusionSource[]
  methodologyProfiles MethodologyProfile[]
  /// Optional MQS row (1:1). Built by `noosphere mqs backfill`; re-runnable
  /// without rewriting the underlying methodology profile.
  methodologyQualityScore MethodologyQualityScore?
  deletionRequests    ConclusionDeletionRequest[]
  dashboardDismissals DashboardDismissal[]

  /// Conclusion edit timestamp; the public MQS pill is only shown when the
  /// MQS row's `scoredAt` is at least this recent.
  updatedAt           DateTime?                   @updatedAt

  @@index([organizationId])
  @@index([organizationId, normalizedText])
}

/// Many-to-many bridge Conclusion ↔ Upload.
///
/// Every conclusion that came out of the ingest pipeline has at least
/// one row here tying it back to the upload it was extracted from.
/// When the SAME normalized text appears in multiple uploads, the
/// ingest pipeline reuses the existing Conclusion row and adds a new
/// ConclusionSource row per additional upload, so the upstream count
/// can drop from 2 → 1 → 0 as uploads are deleted.
///
/// Delete semantics (enforced by the app-side delete handlers, NOT by
/// FK cascade — we soft-delete uploads, so the FK's ON DELETE CASCADE
/// would not fire anyway):
///
///   * When an upload is soft-deleted, every ConclusionSource row
///     with that uploadId is hard-deleted.
///   * After that, any Conclusion with zero remaining rows is
///     hard-deleted too (the claim's last source is gone).
///   * Conclusions with sources from other uploads remain, just
///     with one fewer row.
///
/// The FK cascade below still serves as a safety net for the rare
/// case of a hard-delete (org takedown, privacy-law purge).
model ConclusionSource {
  conclusionId String
  uploadId     String
  createdAt    DateTime @default(now())

  conclusion Conclusion @relation(fields: [conclusionId], references: [id], onDelete: Cascade)
  upload     Upload     @relation(fields: [uploadId], references: [id], onDelete: Cascade)

  @@id([conclusionId, uploadId])
  @@index([conclusionId])
  @@index([uploadId])
}

// ── Publication (SP10) — review queue + versioned public snapshots ───────────

/// Internal gate before a conclusion may appear on the public site.
model PublicationReview {
  id             String @id @default(cuid())
  organizationId String
  conclusionId   String

  /// queued | in_review | needs_revision | declined | published
  status        String @default("queued")
  /// JSON: { metaAnalysisOk, adversarialEngagedOk, clarityOk, noLeakageOk }
  checklistJson String @default("{}")
  reviewerNotes String @default("")
  declineReason String @default("")
  revisionAsk   String @default("")

  reviewerFounderId String?
  createdAt         DateTime @default(now())
  updatedAt         DateTime @updatedAt

  organization Organization @relation(fields: [organizationId], references: [id], onDelete: Restrict)
  target       Conclusion   @relation(fields: [conclusionId], references: [id], onDelete: Cascade)
  reviewer     Founder?     @relation("PublicationReviewer", fields: [reviewerFounderId], references: [id])

  @@index([organizationId])
  @@index([conclusionId])
  @@index([status])
}

/// Immutable-ish public snapshot (new row per material revision).
model PublishedConclusion {
  id                 String @id @default(cuid())
  organizationId     String
  sourceConclusionId String

  slug    String
  version Int    @default(1)
  /// CONCLUSION for reviewed firm conclusions; ARTICLE for generated longform essays.
  kind    String @default("CONCLUSION")

  /// Headline discounted confidence (SP05); stated founder/model confidence alongside in JSON.
  discountedConfidence      Float
  statedConfidence          Float  @default(0)
  calibrationDiscountReason String @default("")

  /// Full page payload: evidence, exit conditions, adversarial, voice map, timeline, citations.
  payloadJson String @default("{}")

  /// Zenodo DOI for this revision (minted on first publish of revision).
  doi            String @default("")
  zenodoRecordId String @default("")

  publishedAt DateTime @default(now())

  organization Organization     @relation(fields: [organizationId], references: [id], onDelete: Restrict)
  responses    PublicResponse[]

  @@unique([slug, version])
  @@index([organizationId])
  @@index([slug])
  @@index([kind, publishedAt])
}

// ── Methodology profiles ───────────────────────────────────────────────────

/// A durable description of how a piece of material reasons, not merely what it
/// concludes. Noosphere writes these from transcripts/uploads and reanalysis
/// scripts; publication review can attach them to public conclusions.
model MethodologyProfile {
  id             String @id @default(cuid())
  organizationId String
  uploadId       String?
  conclusionId   String?

  /// UPLOAD when derived from a transcript/artifact; CONCLUSION when derived
  /// from a conclusion/publication review; MANUAL for founder-authored method
  /// summaries.
  sourceKind String @default("UPLOAD")

  patternType String
  title       String
  summary     String @db.Text

  reasoningMoves  Json
  transferTargets Json
  assumptions     Json
  failureModes    Json
  evidenceAnchors Json

  confidence Float @default(0.5)
  dedupeKey  String

  createdAt DateTime @default(now())
  updatedAt DateTime @updatedAt

  organization Organization @relation(fields: [organizationId], references: [id], onDelete: Restrict)
  upload       Upload?      @relation(fields: [uploadId], references: [id], onDelete: Cascade)
  conclusion   Conclusion?  @relation(fields: [conclusionId], references: [id], onDelete: Cascade)

  @@unique([organizationId, dedupeKey])
  @@index([organizationId, createdAt])
  @@index([organizationId, patternType])
  @@index([uploadId])
  @@index([conclusionId])
}

// ── Methodology Quality Score (MQS) ─────────────────────────────────────────

/// Operational form of the five working criteria from `THE_META_METHOD.md`:
/// progressivity, severity, aim-method fit, compressibility, domain sensitivity.
///
/// One row per Conclusion. The score is additive — it never silently mutates a
/// MethodologyProfile — and re-runnable: `noosphere mqs backfill` overwrites
/// the existing row in place using the conclusion id as the unique key.
///
/// The composite is intentionally not a simple mean. Domain Sensitivity acts
/// as a multiplicative gate; the canonical formula is documented in
/// `docs/methods/MQS_Specification.md` and verified by
/// `scripts/check_mqs_doc_consistency.py`.
model MethodologyQualityScore {
  id             String @id @default(cuid())
  organizationId String

  /// 1:1 with Conclusion. The unique constraint enforces the relation.
  conclusionId String @unique

  progressivity     Float
  severity          Float
  aimMethodFit      Float
  compressibility   Float
  domainSensitivity Float
  composite         Float

  /// JSON blob with one entry per sub-score plus the composite formula and
  /// schema version, so a human reviewer can inspect and contest the score.
  evidence Json

  /// Identity of the producer so re-runs can be reasoned about (e.g.
  /// "anthropic/claude-opus-4-7" + "mqs-prompt-v1.0").
  modelName     String @default("stub")
  promptVersion String @default("mqs-prompt-v1.0")

  scoredAt  DateTime @default(now())
  createdAt DateTime @default(now())
  updatedAt DateTime @updatedAt

  organization Organization @relation(fields: [organizationId], references: [id], onDelete: Restrict)
  conclusion   Conclusion   @relation(fields: [conclusionId], references: [id], onDelete: Cascade)

  @@index([organizationId, scoredAt])
  @@index([organizationId, composite])
}

// ── Currents — observed external events + source-grounded opinions ──────────

model CurrentEvent {
  id              String             @id @default(cuid())
  organizationId  String
  source          CurrentEventSource
  externalId      String
  authorHandle    String?
  text            String             @db.Text
  url             String?
  capturedAt      DateTime           @default(now())
  observedAt      DateTime
  topicHint       String?
  isNearDuplicate Boolean            @default(false)
  embedding       Bytes?
  metrics         Json?
  status          CurrentEventStatus @default(OBSERVED)
  dedupeHash      String             @unique
  createdAt       DateTime           @default(now())
  updatedAt       DateTime           @updatedAt

  organization Organization   @relation(fields: [organizationId], references: [id], onDelete: Restrict)
  opinions     EventOpinion[]

  @@index([organizationId, observedAt])
  @@index([organizationId, status])
}

model EventOpinion {
  id               String            @id @default(cuid())
  organizationId   String
  eventId          String
  stance           OpinionStance
  confidence       Float
  headline         String            @db.VarChar(140)
  bodyMarkdown     String            @db.Text
