// ── ContradictionFinding + scores — mirrors pipeline outputs ────────────────

model Contradiction {
  id             String @id @default(cuid())
  organizationId String

  claimAId     String
  claimBId     String
  severity     Float
  sixLayerJson String?
  narrative    String   @default("")
  createdAt    DateTime @default(now())

  // ── Source tracking ───────────────────────────────────────────────
  // The upload whose ingestion run produced this contradiction row.
  // Nullable so the column can be backfilled from `noosphereId` patterns
  // on existing rows; the ingest pipeline sets it on every new row.
  // When the source upload is deleted the contradiction is hard-deleted
  // in the same transaction (see src/app/api/upload/[id]/delete/route.ts);
  // cross-upload contradictions (where claimA and claimB come from
  // different uploads) additionally die if EITHER of their referenced
  // Conclusions has already been orphan-deleted.
  sourceUploadId String?
  sourceUpload   Upload? @relation("ContradictionSourceUpload", fields: [sourceUploadId], references: [id])

  // ── Resolution tracking ────────────────────────────────────────────
  // A contradiction starts "active". A founder can resolve it
  // (acknowledged + addressed with a note) or dismiss it (false
  // positive). Non-active rows are hidden from the main view by
  // default but preserved for audit.
  status       String    @default("active") // active | resolved | dismissed
  resolution   String?
  resolvedById String?
  resolvedAt   DateTime?
  resolvedBy   Founder?  @relation("ContradictionResolver", fields: [resolvedById], references: [id])

  organization Organization @relation(fields: [organizationId], references: [id], onDelete: Restrict)

  @@index([organizationId])
  @@index([sourceUploadId])
  @@index([status])
}

// ── ConclusionDeletionRequest ─────────────────────────────────────────
// Peer-to-peer "please delete this conclusion" workflow, mirroring
// DeletionRequest for uploads. A founder opens a request; the
// conclusion's attributed founder (or an admin) accepts or declines.
// On accept: hard-delete the Conclusion (and its ConclusionSource rows
// via FK cascade) so it's purged from the model.

model ConclusionDeletionRequest {
  id           String    @id @default(cuid())
  conclusionId String
  requesterId  String
  status       String    @default("pending") // pending | accepted | declined | cancelled
  reason       String?
  decision     String?
  createdAt    DateTime  @default(now())
  respondedAt  DateTime?

  conclusion Conclusion @relation(fields: [conclusionId], references: [id], onDelete: Cascade)
  requester  Founder    @relation(fields: [requesterId], references: [id])

  @@index([conclusionId])
  @@index([requesterId])
  @@index([status])
}

// ── DashboardDismissal ─────────────────────────────────────────────────
// Per-founder UI preference. Dismissing a conclusion from the dashboard
// hides it from *this* founder's homepage only — other founders in the
// same org still see it. Not a deletion.

model DashboardDismissal {
  id           String   @id @default(cuid())
  founderId    String
  conclusionId String
  createdAt    DateTime @default(now())

  founder    Founder    @relation(fields: [founderId], references: [id])
  conclusion Conclusion @relation(fields: [conclusionId], references: [id], onDelete: Cascade)

  @@unique([founderId, conclusionId])
  @@index([founderId])
  @@index([conclusionId])
}

