// ── Multi-tenant root (cloud: Postgres + RLS; local dev: SQLite) ─────────────

model Organization {
  id        String    @id @default(cuid())
  /// URL-safe tenant key (login, subdomains, worker routing)
  slug      String    @unique
  name      String
  /// Soft-delete grace window (hard-delete after policy window)
  deletedAt DateTime?
  createdAt DateTime  @default(now())
  updatedAt DateTime  @updatedAt

  founders             Founder[]
  sessions             Session[]
  uploads              Upload[]
  conclusions          Conclusion[]
  contradictions       Contradiction[]
  driftEvents          DriftEvent[]
  researchSuggestions  ResearchSuggestion[]
  reviewItems          ReviewItem[]
  openQuestions        OpenQuestion[]
  auditEvents          AuditEvent[]
  publicationReviews   PublicationReview[]
  publishedConclusions PublishedConclusion[]
  publicResponses      PublicResponse[]
  apiKeys              ApiKey[]
  currentEvents        CurrentEvent[]
  eventOpinions        EventOpinion[]
  methodologyProfiles  MethodologyProfile[]
  methodologyQualityScores MethodologyQualityScore[]
  socialPosts          SocialPost[]
  operatorStates       OperatorState[]
  forecastMarkets      ForecastMarket[]
  forecastPredictions  ForecastPrediction[]
  forecastTraces       ForecastTrace[]
  forecastBets         ForecastBet[]
  forecastPortfolios   ForecastPortfolioState[]
  watchedMarkets       WatchedMarket[]
  conclusionMethods    ConclusionMethod[]
  methodTrackRecords   MethodTrackRecord[]
}

// ── Founders (portal users) — maps to FounderProfile in noosphere/models.py ─

model Founder {
  id             String       @id @default(cuid())
  organizationId String
  organization   Organization @relation(fields: [organizationId], references: [id], onDelete: Restrict)

  name                    String
  username                String
  email                   String
  passwordHash            String
  // Role ladder — see src/lib/roles.ts for the predicate helpers and
  // the full description of each tier:
  //   admin   → full read + write + can change other founders' roles
  //   founder → full read + write
  //   viewer  → read-only; every write API returns 403 and every UI
  //              affordance for writes is hidden
  // Default "founder" preserves prior behaviour: anyone added via
  // scripts/add-founder.ts is read+write unless explicitly seeded
  // with ADD_FOUNDER_ROLE=viewer or =admin. Validation lives at the
  // application layer; the column stays TEXT so adding a future tier
  // is a docstring + helper change, not a migration.
  role                    String    @default("founder") // admin | founder | viewer
  bio                     String?
  displayName             String?
  roleTitle               String?
  publicUrl               String?
  avatar                  String?
  accountNudgeDismissedAt DateTime?

  /// Maps to FounderProfile.id in Noosphere
  noosphereId String?

  createdAt DateTime @default(now())
  updatedAt DateTime @updatedAt

  sessions                   Session[]
  uploads                    Upload[]
  auditEvents                AuditEvent[]
  deletionRequests           DeletionRequest[]
  attributedConclusions      Conclusion[]                @relation("ConclusionFounder")
  researchSuggestions        ResearchSuggestion[]
  reviewResolutions          ReviewItem[]                @relation("ReviewResolver")
  publicationReviews         PublicationReview[]         @relation("PublicationReviewer")
  apiKeys                    ApiKey[]
  conclusionDeletionRequests ConclusionDeletionRequest[]
  dashboardDismissals        DashboardDismissal[]
  resolvedContradictions     Contradiction[]             @relation("ContradictionResolver")

  @@unique([organizationId, email])
  @@unique([organizationId, username])
  @@index([organizationId])
}

/// Browser session (server-side row; cookie carries signed opaque token)
model Session {
  id             String   @id @default(cuid())
  organizationId String
  founderId      String
  token          String   @unique
  expiresAt      DateTime
  createdAt      DateTime @default(now())

  founder      Founder      @relation(fields: [founderId], references: [id], onDelete: Cascade)
  organization Organization @relation(fields: [organizationId], references: [id], onDelete: Restrict)

  @@index([organizationId])
  @@index([founderId])
}

// ── Uploads ────────────────────────────────────────────────────────────────

model Upload {
  id             String @id @default(cuid())
  organizationId String
  founderId      String

  title            String
  description      String?
  sourceType       String   @default("written") // written | annotation | external | transcript
  originalName     String
  mimeType         String
  filePath         String
  fileSize         Int
  textContent      String?
  blurb            String?
  // Status ladder (see src/lib/uploadStatus.ts for the canonical
  // vocabulary + UI labels). `pending | processing | ingested | failed`
  // are load-bearing strings from the init migration; `extracting` and
  // `awaiting_ingest` were added alongside the Wave-1 audio/PDF
  // extractors so founders can see which stage of the pipeline a row is
  // in (Whisper/pypdf vs. claim extraction) instead of a single opaque
  // "processing".
  status           String   @default("pending") // pending | extracting | awaiting_ingest | processing | ingested | failed
  processLog       String   @default("") // streamed CLI stdout/stderr
  claimsCount      Int?
  methodCount      Int?
  substCount       Int?
  principleCount   Int?
  errorMessage     String?
  // How the text was obtained for this upload, set by the noosphere
  // extractor dispatcher on success. Free-form string — e.g.
  // "passthrough", "faster-whisper", "openai-whisper-1", "pypdf",
  // "ocrmypdf". Rendered in the dashboard detail row so the founder
  // knows whether a transcript/PDF extract was reliable.
  extractionMethod String?
  createdAt        DateTime @default(now())
  updatedAt        DateTime @updatedAt

  // ── Public blog fields ─────────────────────────────────────────────
  // An Upload becomes a public blog post when `publishedAt IS NOT NULL`.
  // Default is null → the upload remains a private founder artifact.
  // `slug` is the URL-safe identifier used for `/post/:slug`; it's
  // generated from `title` at publish time and guaranteed unique across
  // the whole table (not per-org — the blog is a single public surface).
  // `blogExcerpt` is the card/list summary shown on the index; if null
  // we derive one from the first ~280 chars of `textContent`.
  // `authorBio` lets the founder override the displayed byline (e.g.
  // for guest posts or co-authored work); otherwise we show
  // Founder.name.
  publishedAt DateTime?
  slug        String?   @unique
  blogExcerpt String?
  authorBio   String?

  // ── Soft delete ────────────────────────────────────────────────────
  // `deletedAt` is the single source of truth for "this upload has
  // been removed". Every query that surfaces uploads to the UI must
  // filter by `deletedAt IS NULL`; we keep the row around so the audit
  // trail (AuditEvent pointing at this upload) stays intact, and so a
  // DB-level restore is possible if a deletion turns out to be a
  // mistake. Only the uploader can set this directly; peers must go
  // through a DeletionRequest, which the owner accepts (setting
  // `deletedAt=now`) or declines.
  deletedAt DateTime?

  // ── Visibility inside the firm ─────────────────────────────────────
  // Three-level visibility ladder. Every value still lets Noosphere
  // run ingestion — conclusions, contradictions, open questions, and
  // research suggestions are always extracted. The levels only
  // control *who reads the upload's metadata and contents*.
  //
  // "org"          → visible to every founder in the organization AND
  //                   eligible for blog publication. The default;
  //                   library, dashboard, peer deletion requests, and
  //                   the blog's publishAsPost toggle all apply.
  //
  // "semi-private" → visible to every founder in the organization,
  //                   but never publishable to the public blog. The
  //                   intermediate level, for material the firm wants
  //                   to discuss internally but that must never leak
  //                   outside. /api/publish rejects the flip; the
  //                   public blog index + /post/[slug] both filter
  //                   it out; /library and /dashboard render it with
  //                   a "semi-private" badge so peers know the
  //                   constraint.
  //
  // "private"      → only the uploader can see the row anywhere in
  //                   the UI; Noosphere still ingests it so the owner
  //                   gets their own conclusions/contradictions, but
  //                   nobody else can see the file, read it, or open
  //                   a deletion request against it. Blog-publishing
  //                   a private upload is rejected at the API layer
  //                   — flip visibility first.
  //
  // Column stays TEXT with default "org" so no migration is needed
  // when new levels are introduced; validation happens at the API
  // layer.
  visibility String @default("org")

  // ── Podcast / audio playback ───────────────────────────────────────
  // When an audio upload is stored in a public CDN-addressable
  // location (Supabase Storage in our case), we persist the public
  // URL here so /post/[slug] can render a <audio controls> player
  // alongside the transcript. `audioDurationSec` is optional
  // metadata derived from ffprobe / client-side duration detection
  // when available; the UI falls back to the player's own duration
  // readout if it's null. Both fields are null for non-audio rows
  // and for audio rows uploaded before Supabase Storage was
  // configured — the blog post still renders, just text-only.
  audioUrl         String?
  audioDurationSec Int?

  founder             Founder              @relation(fields: [founderId], references: [id])
  organization        Organization         @relation(fields: [organizationId], references: [id], onDelete: Restrict)
  chunks              UploadChunk[]
  auditEvents         AuditEvent[]
  deletionRequests    DeletionRequest[]
  // ── Provenance back-refs ─────────────────────────────────────────
  // Derived entities (Conclusions via the M:N join, Contradictions,
  // OpenQuestions, ResearchSuggestions directly) point back here so
  // the delete path can cascade-clean any artifact whose source has
  // been removed. `conclusionSources` is the many-to-many bridge —
  // the same text can be extracted from multiple uploads, and each
  // upload holds its own row in the bridge. The direct sourceUpload
  // relations on the other three entities are one-per-row: a
  // contradiction / open-question / research suggestion is an output
  // of exactly one ingestion run, even when it references claims from
  // multiple uploads.
  conclusionSources   ConclusionSource[]
  methodologyProfiles MethodologyProfile[]
  contradictions      Contradiction[]      @relation("ContradictionSourceUpload")
  openQuestions       OpenQuestion[]       @relation("OpenQuestionSourceUpload")
  researchSuggestions ResearchSuggestion[] @relation("ResearchSuggestionSourceUpload")

  @@index([organizationId])
  @@index([founderId])
  @@index([publishedAt])
  @@index([deletedAt])
  @@index([visibility])
  // Dashboard filters by status constantly (ingested rows on the main
  // panel, failed/pending counts on the banner). A plain btree index
  // is enough — the org-scope is already covered by organizationId.
  @@index([status])
}

model UploadChunk {
  id           String  @id @default(cuid())
  uploadId     String
  index        Int
  text         String
  startMs      Int?
  endMs        Int?
  speakerLabel String?
  headingHint  String?
  createdAt    DateTime @default(now())
  updatedAt    DateTime @updatedAt

  upload Upload @relation(fields: [uploadId], references: [id], onDelete: Cascade)

  @@unique([uploadId, index])
  @@index([uploadId])
}

// ── DeletionRequest ───────────────────────────────────────────────────
// Peer-to-peer "please delete this" workflow. A founder who doesn't own
// an upload but wants it removed opens a request against that upload;
// the owner reviews it (accept → soft-delete the upload, decline → log
// reason and keep). The requester can cancel their own request at any
// time before the owner responds.
//
// Enforcement:
//   * Requester.organizationId must equal Upload.organizationId (done
//     at route-handler level, not schema — cross-org requests are
//     structurally unreachable via UI anyway).
//   * Requester.id MUST NOT equal Upload.founderId (an owner deletes
//     their own upload directly via DELETE /api/uploads/:id; opening
//     a request against yourself is noise).
//   * At most one ACTIVE (status=pending) request per (upload, requester)
//     pair — the unique partial-index is added in the migration SQL.

model DeletionRequest {
  id          String    @id @default(cuid())
  uploadId    String
  requesterId String
  status      String    @default("pending") // pending | accepted | declined | cancelled
  reason      String?
  decision    String? // optional note from the owner when accepting/declining
  createdAt   DateTime  @default(now())
  respondedAt DateTime?

  upload    Upload  @relation(fields: [uploadId], references: [id], onDelete: Cascade)
  requester Founder @relation(fields: [requesterId], references: [id])

  @@index([uploadId])
  @@index([requesterId])
  @@index([status])
}

// ── Conclusion — mirrors noosphere.models.Conclusion ───────────────────────

model Conclusion {
  id             String @id @default(cuid())
  organizationId String

  /// Stable id if synced from / produced for Noosphere
  noosphereId String? @unique
  text        String

  // ── Dedup key ──────────────────────────────────────────────────────
  // `normalizedText` is `LOWER(TRIM(REGEXP_REPLACE(text, '\s+', ' ')))`
  // computed once at ingest time. The ingest pipeline checks for an
  // existing Conclusion in the same org with a matching normalizedText;
  // if one exists, it adds the current upload as an ADDITIONAL source
  // via ConclusionSource rather than inserting a duplicate row. That's
  // what makes deletion correct: when two uploads produced the same
  // claim and we delete one, the conclusion stays — it's still
  // supported by the other source.
  //
  // Nullable so the column can be added to an existing DB without a
  // rewrite; the migration back-fills every existing row. Indexed
  // `(organizationId, normalizedText)` because every lookup is scoped
  // to a single org.
  normalizedText         String?
  confidenceTier         String // firm | founder | open (ConfidenceTier)
  rationale              String   @default("")
  supportingPrincipleIds String   @default("[]") // JSON string[]
  evidenceChainClaimIds  String   @default("[]")
  dissentClaimIds        String   @default("[]")
  confidence             Float    @default(0)
  topicHint              String   @default("") // UI filter / display
  createdAt              DateTime @default(now())

  /// JSON-serialized float[] embedding produced by Noosphere's sentence
  /// encoder at ingest time. Null for conclusions ingested before this
  /// column was added; the semantic explorer backfills on demand.
  embeddingJson String?

  attributedFounderId String?
  attributedFounder   Founder?                    @relation("ConclusionFounder", fields: [attributedFounderId], references: [id])
  organization        Organization                @relation(fields: [organizationId], references: [id], onDelete: Restrict)
  publicationReviews  PublicationReview[]
  sources             ConclusionSource[]
  methodologyProfiles MethodologyProfile[]
  /// Optional MQS row (1:1). Built by `noosphere mqs backfill`; re-runnable
  /// without rewriting the underlying methodology profile.
  methodologyQualityScore MethodologyQualityScore?
  conclusionMethods   ConclusionMethod[]
  deletionRequests    ConclusionDeletionRequest[]
  dashboardDismissals DashboardDismissal[]

  /// Conclusion edit timestamp; the public MQS pill is only shown when the
  /// MQS row's `scoredAt` is at least this recent.
  updatedAt           DateTime?                   @updatedAt

  @@index([organizationId])
  @@index([organizationId, normalizedText])
}

/// Many-to-many bridge Conclusion ↔ Upload.
///
/// Every conclusion that came out of the ingest pipeline has at least
/// one row here tying it back to the upload it was extracted from.
/// When the SAME normalized text appears in multiple uploads, the
/// ingest pipeline reuses the existing Conclusion row and adds a new
/// ConclusionSource row per additional upload, so the upstream count
/// can drop from 2 → 1 → 0 as uploads are deleted.
///
/// Delete semantics (enforced by the app-side delete handlers, NOT by
/// FK cascade — we soft-delete uploads, so the FK's ON DELETE CASCADE
/// would not fire anyway):
///
///   * When an upload is soft-deleted, every ConclusionSource row
///     with that uploadId is hard-deleted.
///   * After that, any Conclusion with zero remaining rows is
///     hard-deleted too (the claim's last source is gone).
///   * Conclusions with sources from other uploads remain, just
///     with one fewer row.
///
/// The FK cascade below still serves as a safety net for the rare
/// case of a hard-delete (org takedown, privacy-law purge).
model ConclusionSource {
  conclusionId String
  uploadId     String
  createdAt    DateTime @default(now())

  conclusion Conclusion @relation(fields: [conclusionId], references: [id], onDelete: Cascade)
  upload     Upload     @relation(fields: [uploadId], references: [id], onDelete: Cascade)

  @@id([conclusionId, uploadId])
  @@index([conclusionId])
  @@index([uploadId])
}

// ── Publication (SP10) — review queue + versioned public snapshots ───────────

/// Internal gate before a conclusion may appear on the public site.
model PublicationReview {
  id             String @id @default(cuid())
  organizationId String
  conclusionId   String

  /// queued | in_review | needs_revision | declined | published
  status        String @default("queued")
  /// JSON: { metaAnalysisOk, adversarialEngagedOk, clarityOk, noLeakageOk }
  checklistJson String @default("{}")
  reviewerNotes String @default("")
  declineReason String @default("")
  revisionAsk   String @default("")

  reviewerFounderId String?
  createdAt         DateTime @default(now())
  updatedAt         DateTime @updatedAt

  organization Organization @relation(fields: [organizationId], references: [id], onDelete: Restrict)
  target       Conclusion   @relation(fields: [conclusionId], references: [id], onDelete: Cascade)
  reviewer     Founder?     @relation("PublicationReviewer", fields: [reviewerFounderId], references: [id])

  @@index([organizationId])
  @@index([conclusionId])
  @@index([status])
}

/// Immutable-ish public snapshot (new row per material revision).
model PublishedConclusion {
  id                 String @id @default(cuid())
  organizationId     String
  sourceConclusionId String

  slug    String
  version Int    @default(1)
  /// CONCLUSION for reviewed firm conclusions; ARTICLE for generated longform essays.
  kind    String @default("CONCLUSION")

  /// Headline discounted confidence (SP05); stated founder/model confidence alongside in JSON.
  discountedConfidence      Float
  statedConfidence          Float  @default(0)
  calibrationDiscountReason String @default("")

  /// Full page payload: evidence, exit conditions, adversarial, voice map, timeline, citations.
  payloadJson String @default("{}")

  /// Zenodo DOI for this revision (minted on first publish of revision).
  doi            String @default("")
  zenodoRecordId String @default("")

  publishedAt DateTime @default(now())

  organization Organization     @relation(fields: [organizationId], references: [id], onDelete: Restrict)
  responses    PublicResponse[]

  @@unique([slug, version])
  @@index([organizationId])
  @@index([slug])
  @@index([kind, publishedAt])
}

// ── Methodology profiles ───────────────────────────────────────────────────

/// A durable description of how a piece of material reasons, not merely what it
/// concludes. Noosphere writes these from transcripts/uploads and reanalysis
/// scripts; publication review can attach them to public conclusions.
model MethodologyProfile {
  id             String @id @default(cuid())
  organizationId String
  uploadId       String?
  conclusionId   String?

  /// UPLOAD when derived from a transcript/artifact; CONCLUSION when derived
  /// from a conclusion/publication review; MANUAL for founder-authored method
  /// summaries.
  sourceKind String @default("UPLOAD")

  patternType String
  title       String
  summary     String @db.Text

  reasoningMoves  Json
  transferTargets Json
  assumptions     Json
  failureModes    Json
  evidenceAnchors Json

  confidence Float @default(0.5)
  dedupeKey  String

  createdAt DateTime @default(now())
  updatedAt DateTime @updatedAt

  organization Organization @relation(fields: [organizationId], references: [id], onDelete: Restrict)
  upload       Upload?      @relation(fields: [uploadId], references: [id], onDelete: Cascade)
  conclusion   Conclusion?  @relation(fields: [conclusionId], references: [id], onDelete: Cascade)

  @@unique([organizationId, dedupeKey])
  @@index([organizationId, createdAt])
  @@index([organizationId, patternType])
  @@index([uploadId])
  @@index([conclusionId])
}

// ── Methodology Quality Score (MQS) ─────────────────────────────────────────

/// Operational form of the five working criteria from `THE_META_METHOD.md`:
/// progressivity, severity, aim-method fit, compressibility, domain sensitivity.
///
/// One row per Conclusion. The score is additive — it never silently mutates a
/// MethodologyProfile — and re-runnable: `noosphere mqs backfill` overwrites
/// the existing row in place using the conclusion id as the unique key.
///
/// The composite is intentionally not a simple mean. Domain Sensitivity acts
/// as a multiplicative gate; the canonical formula is documented in
/// `docs/methods/MQS_Specification.md` and verified by
/// `scripts/check_mqs_doc_consistency.py`.
model MethodologyQualityScore {
  id             String @id @default(cuid())
  organizationId String

  /// 1:1 with Conclusion. The unique constraint enforces the relation.
  conclusionId String @unique

  progressivity     Float
  severity          Float
  aimMethodFit      Float
  compressibility   Float
  domainSensitivity Float
  composite         Float

  /// JSON blob with one entry per sub-score plus the composite formula and
  /// schema version, so a human reviewer can inspect and contest the score.
  evidence Json

  /// Identity of the producer so re-runs can be reasoned about (e.g.
  /// "anthropic/claude-opus-4-7" + "mqs-prompt-v1.0").
  modelName     String @default("stub")
  promptVersion String @default("mqs-prompt-v1.0")

  scoredAt  DateTime @default(now())
  createdAt DateTime @default(now())
  updatedAt DateTime @updatedAt

  organization Organization @relation(fields: [organizationId], references: [id], onDelete: Restrict)
  conclusion   Conclusion   @relation(fields: [conclusionId], references: [id], onDelete: Cascade)

  @@index([organizationId, scoredAt])
  @@index([organizationId, composite])
}

// ── Currents — observed external events + source-grounded opinions ──────────

model CurrentEvent {
  id              String             @id @default(cuid())
  organizationId  String
  source          CurrentEventSource
  externalId      String
  authorHandle    String?
  text            String             @db.Text
  url             String?
  capturedAt      DateTime           @default(now())
  observedAt      DateTime
  topicHint       String?
  isNearDuplicate Boolean            @default(false)
  embedding       Bytes?
  metrics         Json?
  status          CurrentEventStatus @default(OBSERVED)
  dedupeHash      String             @unique
  createdAt       DateTime           @default(now())
  updatedAt       DateTime           @updatedAt

  organization Organization   @relation(fields: [organizationId], references: [id], onDelete: Restrict)
  opinions     EventOpinion[]

  @@index([organizationId, observedAt])
  @@index([organizationId, status])
}

model EventOpinion {
  id               String            @id @default(cuid())
  organizationId   String
  eventId          String
  stance           OpinionStance
  confidence       Float
  headline         String            @db.VarChar(140)
  bodyMarkdown     String            @db.Text
  uncertaintyNotes String[]
  topicHint        String?
  modelName        String
  promptTokens     Int               @default(0)
  completionTokens Int               @default(0)
  abstentionReason AbstentionReason?
  generatedAt      DateTime          @default(now())
  revokedAt        DateTime?
  revokedReason    String?

  organization     Organization      @relation(fields: [organizationId], references: [id], onDelete: Restrict)
  event            CurrentEvent      @relation(fields: [eventId], references: [id], onDelete: Cascade)
  citations        OpinionCitation[]
  followUpSessions FollowUpSession[]

  @@index([organizationId, generatedAt])
  @@index([eventId])
}

model OpinionCitation {
  id             String    @id @default(cuid())
  opinionId      String
  sourceKind     String
  conclusionId   String?
  claimId        String?
  quotedSpan     String    @db.Text
  retrievalScore Float
  justificationMetadata Json      @default("{}")
  isRevoked      Boolean   @default(false)
  revokedAt      DateTime?
  revokedReason  String?

  opinion EventOpinion @relation(fields: [opinionId], references: [id], onDelete: Cascade)

  @@index([opinionId])
  @@index([conclusionId])
  @@index([claimId])
}

model FollowUpSession {
  id                String   @id @default(cuid())
  opinionId         String
  clientFingerprint String
  createdAt         DateTime @default(now())
  lastActivityAt    DateTime @default(now())

  opinion  EventOpinion      @relation(fields: [opinionId], references: [id], onDelete: Cascade)
  messages FollowUpMessage[]

  @@index([opinionId, lastActivityAt])
  @@index([clientFingerprint, createdAt])
}

model FollowUpMessage {
  id        String       @id @default(cuid())
  sessionId String
  role      FollowUpRole
  content   String       @db.Text
  citations Json?
  createdAt DateTime     @default(now())

  session FollowUpSession @relation(fields: [sessionId], references: [id], onDelete: Cascade)

  @@index([sessionId, createdAt])
}

// ── Social publishing — held outbound posts with a hard human gate ─────────

model SocialPost {
  id             String   @id @default(cuid())
  organizationId String
  createdAt      DateTime @default(now())
  source         String
  sourceId       String?
  platform       String
  bundleId       String?  @db.Uuid
  body           String   @db.Text
  markdownBody   String?  @db.Text
  subject        String?
  media          Json?
  status         String
  approvedBy     String?
  approvedAt     DateTime?
  postedAt       DateTime?
  externalId     String?
  failureReason  String?

  organization Organization @relation(fields: [organizationId], references: [id], onDelete: Restrict)

  @@index([organizationId, status, createdAt])
  @@index([platform, status, postedAt])
  @@index([source, sourceId])
  @@index([bundleId])
}

model OperatorState {
  id             String   @id @default(cuid())
  organizationId String
  key            String
  value          Json
  createdAt      DateTime @default(now())
  updatedAt      DateTime @updatedAt

  organization Organization @relation(fields: [organizationId], references: [id], onDelete: Restrict)

  @@unique([organizationId, key])
  @@index([key])
}

// ── Forecasts — external prediction markets + source-grounded predictions ───

model ForecastMarket {
