      <main className="public-container public-methodology-page">
        <Link href="/methodology" className="public-muted" style={{ fontSize: "0.75rem" }}>
          ← Methodology
        </Link>
        <h1 className="public-title" style={{ marginTop: "0.5rem" }}>
